1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	const BLOCK_SIZE = 3;
17	const BLOCK_PREMIUM = 60;
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	
20	const groupByType = (items: Item[]): Map<string, Item[]> => {
21	  const groups = new Map<string, Item[]>();
22	  for (const item of items) {
23	    const group = groups.get(item.type) ?? [];
24	    group.push(item);
25	    groups.set(item.type, group);
26	  }
27	  return groups;
28	};
29	
30	const premiumForGroup = (type: string, group: Item[]) => {
31	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
32	    return BLOCK_PREMIUM;
33	  }
34	  return group.length * BASE_PREMIUM[type];
35	};
36	
37	const basePremiumFor = (items: Item[]) =>
38	  [...groupByType(items)].reduce(
39	    (total, [type, group]) => total + premiumForGroup(type, group),
40	    0,
41	  );
42	
43	const FIRST_INSURANCE_RATE = 0.1;
44	
45	const quote = (step: QuoteStep) => {
46	  const base = basePremiumFor(step.items);
47	  const premium =
48	    base === 0 ? 0 : base + base * FIRST_INSURANCE_RATE;
49	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
50	};
51	
52	export const run = (input: Scenario): unknown => ({
53	  results: input.steps.map(quote),
54	});
55

